final class DeliveryHttp{public array$c=[];public function send(string$url,string$method='GET',array$data=[]):array{$h=[];if($this->c)$h[]='Cookie: '.implode('; ',array_map(fn($k,$v)=>$k.'='.$v,array_keys($this->c),$this->c));$o=['method'=>$method,'ignore_errors'=>true,'follow_location'=>0];if($method==='POST'){$h[]='Content-Type: application/x-www-form-urlencoded';$o['content']=http_build_query($data);}$o['header']=implode("\r\n",$h);$body=file_get_contents($url,false,stream_context_create(['http'=>$o]));$rh=$http_response_header??[];foreach($rh as$x)if(preg_match('/^Set-Cookie:\s*([^=]+)=([^;]*)/i',$x,$m))$this->c[$m[1]]=$m[2];preg_match('/\s(\d{3})\s/',$rh[0]??'',$m);$loc='';foreach($rh as$x)if(str_starts_with(strtolower($x),'location:'))$loc=trim(substr($x,9));return[(int)($m[1]??0),(string)$body,$loc];}}
