r_id'=>$scannerId,'movement'=>$movement,'response_has_success'=>str_contains($result,'Entrega registrada'),'response_message'=>preg_match('/vo-alert[^>]*>.*?<p>(.*?)<\/p>/s',$result,$m)?trim(strip_tags($m[1])):null,'payload_fields'=>array_keys($payload)],JSON_PRETTY_PRINT|JSON_UNESCAPED_UNICODE).PHP_EOL;}finally{if($movementId){$s=$pdo->query("SELECT ruta_storage FROM scanner_evidencias WHERE movimiento_id=$movementId");$paths=$s->fetchAll(PDO::FETCH_COLUMN);$pdo->exec("DELETE FROM auditoria_eventos WHERE entidad='scanner_movement' AND entidad_id=$movementId");$pdo->exec("DELETE FROM scanner_inspeccion_detalles WHERE inspeccion_id IN (SELECT id FROM scanner_inspecciones WHERE movimiento_id=$movementId)");$pdo->exec("UPDATE scanner_inspecciones SET firma_usuario_evidencia_id=NULL,firma_responsable_evidencia_id=NULL WHERE movimiento_id=$movementId");$pdo->exec("DELETE FROM scanner_evidencias WHERE movimiento_id=$movementId");$pdo->exec("DELETE FROM scanner_inspecciones WHERE movimiento_id=$movementId");$pdo->exec("DELETE FROM scanner_movimientos WHERE id=$movementId");}$pdo->exec("DELETE FROM scanner_estado_historial WHERE scanner_id=".(int)$scannerId);if($scannerId)$pdo->exec("DELETE FROM scanners WHERE id=$scannerId");foreach($paths as$p){$absolute=dirname(__DIR__,2).'/storage/evidencias/control-escaneres/'.str_replace(['..','\\'],['','/'],(string)$p);if(is_file($absolute))unlink($absolute);}}
